const d = $json || {};
const h = d.headers || {};
const b = (d.body && typeof d.body === 'object') ? d.body : {};
const q = d.query || {};
const pick = (k) => (h[k] || b[k] || q[k] || '').toString().trim();

const msg = (h.last_text_input || b.last_text_input || b.message || b.text || b.last_input_text || b.last_input || b.user_message || b.msg || q.last_text_input || q.message || q.text || '').toString().replace(/^\s*\.+\s*/, '').trim();

const first_name = pick('system_firstname');
const last_name  = pick('system_lastname');
const email      = pick('system_email');
const phone      = pick('system_phone');
const subscribed_date = pick('contact_subscribed_date');

// real display: new tiktok_display, then legacy tiktok_displayname, then the contact's name
const fullName = (first_name + ' ' + last_name).trim();
const display = pick('tiktok_display') || (h.tiktok_displayname || b.display_name || '').toString().trim() || fullName || first_name || '';
const username = (h.tiktok_username || b.username || q.username || pick('tiktok_username') || display || 'unknown').toString().toLowerCase();
const subscriber_id = (h.subscriber_id || b.subscriber_id || b.user_id || q.subscriber_id || q.user_id || '').toString().trim();
const interaction = (h.tiktok_lastinteraction || b.tiktok_lastinteraction || q.tiktok_lastinteraction || '').toString().trim();

return [{ json: { username, display, subscriber_id, msg: msg || '(he sent a sticker or an empty message, greet him and tease him lightly)', interaction, first_name, last_name, email, phone, subscribed_date } }];

// duplicate guard: ManyChat / TikTok sometimes re-delivers the same inbound
// message minutes apart. each real message carries a tiktok_lastinteraction
// timestamp; a re-delivery repeats it. if we already handled this exact
// interaction for this fan, drop it silently so she does not reply twice.
const ex = $('Extract Inbound').first().json;
const items = $('Dedup: read fan').all();
let meta = {};
if (items.length === 1 && Array.isArray(items[0].json)) { if (items[0].json.length) meta = items[0].json[0].metadata || {}; }
else if (items.length && items[0].json && items[0].json.metadata) { meta = items[0].json.metadata || {}; }
const last = (meta && meta.last_interaction_ts) ? String(meta.last_interaction_ts) : '';
const cur = ex.interaction ? String(ex.interaction) : '';
if (cur && last && cur === last) { return []; }
return [{ json: ex }];

// human-feeling delay before she replies. timing + pause are PER-PERSONA, set in
// the admin dashboard (bots.reply_delay / bots.automation_paused) and returned by
// dm_ingest. See automation/n8n/REPLY_TIMING.md + PAUSE_GATE.md.
const ctx = $('DB: ingest').first().json || {};

// pause: dashboard toggled this bot off -> inbound already logged by dm_ingest,
// just don't queue or reply.
if (ctx.automation_paused === true) { return []; }

const d = ctx.reply_delay || {};
const num = (v, dft) => (Number.isFinite(Number(v)) ? Number(v) : dft);
const minS = num(d.min_sec, 120);
const maxS = num(d.max_sec, 600);
const qP   = num(d.quick_chance, 0.15);
const qMin = num(d.quick_min_sec, 45);
const qMax = num(d.quick_max_sec, 120);

let sec;
if (Math.random() < qP) { sec = Math.round(qMin + Math.random() * Math.max(0, qMax - qMin)); }
else { sec = Math.round(minS + Math.random() * Math.max(0, maxS - minS)); }

const ex = $('Extract Inbound').first().json || {};
const now = Date.now();
return [{ json: { delaySec: sec, myCount: ctx.count, fan_id: ctx.fan_id, bot_id: ctx.bot_id, subscriber_id: ex.subscriber_id, username: ex.username, display: ex.display, msg: ex.msg, queued_at: new Date(now).toISOString(), scheduled_for: new Date(now + sec * 1000).toISOString() } }];

// debounce: only the LAST inbound message in a burst gets to reply.
// if msg_count grew while we were waiting, a newer message arrived;
// abort this run (return []) and let the newer run answer with full context.
const arr = $json;
const cur = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
const myCount = $('Set Delay').first().json.myCount;
if (typeof cur.msg_count !== 'number' || cur.msg_count !== myCount) { return []; }
return [{ json: { proceed: true } }];

const ctx = $('DB: ingest').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
const last = recent.length ? recent[recent.length - 1].content : '';
const history = recent.slice(-7).map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; }).join('\n');
const turns = recent.length;
const sys = [
'you are a fast silent classifier for a flirty 21yo female texting persona named candace, talking to a man in her dms. she is the prize: cool, hard to get, never eager. her endgame is to lead him to her private telegram @candace_summers. you never write her reply. you output one json object only, nothing else.',
'read his latest message and the recent context, then output exactly this json:',
'{',
'"archetype": one of [sweet, cocky, shy, provider, submissive, lowffort, hostile, normal],',
'"intent": one of [greeting, compliment, question_about_her, question_other, sexual, bot_test, wants_more, wants_to_meet, wants_personal_info, vulnerable, boring, insult, normal],',
'"effort": one of [low, medium, high],',
'"funnel": boolean. true only when it is the right moment to lead him toward the telegram (he asked for more, onlyfans, snap, other socials, where to find her, to see more, or he is clearly hooked and flirty). false otherwise. do not funnel a guy who just said hey.',
'"ask_back": boolean. DEFAULT false. true only about one in five, never if his last reply was a question, never if he is low effort, never on a compliment or question_about_her.',
'"directive": a short specific instruction, max 22 words, for how candace plays THIS reply. she is the prize, never gushes, never over shares, never interviews him.',
'}',
'directive guidance by case:',
'- wants_more (asks about onlyfans, snapchat, whatsapp, other socials, where else can i find you, can i see more of you, or getting flirty and clearly wanting more): set funnel true. lead him to her telegram, but make it sound like a real girl casually giving her username, never a pitch. give the username plainly as candace_summers with no @ symbol, no link, no call to action tacked on. do NOT explain why its good, do NOT add if you earn it every time. prefer she mentions shes barely on this app and more on telegram and let him ask. keep it casual and a little reluctant. never mention money. if the chat is brand new with almost no spark yet (' + turns + ' turns so far), tease the telegram and make him earn it instead of handing it over.',
'- compliment: receive it coolly and confidently, a little smug, never gush.',
'- question_about_her: brief and coy, a crumb not a paragraph, no interview back.',
'- low effort or greeting with nothing behind it: short flat reply, give less.',
'- cocky or flexing money or status: tease, act unimpressed, make him work.',
'- submissive or asks to be owned: deny and make him earn it, cool and in control.',
'- vulnerable: a little real warmth, draw him out gently.',
'- bot_test: confident playful deflection.',
'- wants_to_meet or wants_personal_info: coy non answer, she does not give it up.',
'- insult or hostile: unbothered amused one liner, never defensive.'
].join('\n');
const usr = 'his latest message: ' + (last || '(empty or sticker)') + '\nrecent conversation oldest first:\n' + (history || '(none)') + '\noutput the json now.';
return [{ json: { classifyMessages: [{ role: 'system', content: sys }, { role: 'user', content: usr }] } }];

const ctx = $('DB: ingest').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
let cls = {};
try { const raw = ($json && $json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ? $json.choices[0].message.content : '{}'; cls = JSON.parse(raw); } catch (e) { cls = {}; }
const archetype = cls.archetype || 'normal';
const effort = cls.effort || 'medium';
const intent = cls.intent || 'normal';
const askBack = (cls.ask_back === true);
const directive = cls.directive || 'stay cool and playful, be the prize, keep it short.';
const brain = (ctx.system_prompt && ctx.system_prompt.length > 50) ? ctx.system_prompt : 'you are candace, a flirty 21yo from columbus ohio. all lowercase, short, no dashes, barely any emoji, you are the prize, never eager.';
const model = (ctx.model && ctx.model.length) ? ctx.model : 'gpt-4o';
const messages = [{ role: 'system', content: brain }];
if (ctx.summary && ctx.summary.length) messages.push({ role: 'system', content: 'your private read on him, who he is and where things are at, use it: ' + ctx.summary });
const read = 'your read on him for THIS reply. he seems ' + archetype + ', his effort is ' + effort + ', he is ' + intent + '. ' + (askBack ? 'you may end with a question if it genuinely fits.' : 'do NOT end this reply with a question, make a statement.') + ' directive: ' + directive + ' follow this while staying fully in your voice.';
messages.push({ role: 'system', content: read });
const st = ctx.stage || 'rapport';
if (st === 'funnelled') messages.push({ role: 'system', content: 'STAGE NOTE: you have ALREADY given him your telegram @candace_summers. do not pitch it again like it is new and do not re-explain it. if he has not gone yet, playfully nudge him to actually come find you over there, tease that you are waiting. keep pulling him toward going.' });
else if (st === 'converted') messages.push({ role: 'system', content: 'STAGE NOTE: he has come to your telegram. keep him warm and a little more rewarding now, make him glad he came.' });
for (const t of recent) { if (t && t.role && t.content) messages.push({ role: t.role, content: t.content }); }
const count = ctx.count || 0;
return [{ json: { messages: messages, model: model, fan_id: ctx.fan_id, bot_id: ctx.bot_id, count: count, stage: st, archetype: archetype } }];

const d = $json || {};
let reply = '';
try { reply = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : ''; } catch (e) { reply = ''; }
reply = (reply || '').trim();
const dq = String.fromCharCode(34);
if (reply.length > 1 && reply.charAt(0) === dq && reply.charAt(reply.length - 1) === dq) { reply = reply.slice(1, -1).trim(); }
const allowed = ['\u{1F60F}', '\u{1F92D}', '\u{1F90D}', '\u{1F440}'];
let ec = 0;
reply = reply.replace(/\p{Extended_Pictographic}/gu, function (m) { if (allowed.indexOf(m) === -1) return ''; ec++; return ec > 1 ? '' : m; });
reply = reply.replace(/[\u{FE0F}\u{200D}]/gu, '');
reply = reply.replace(/\s*[\u2014\u2013]\s*/g, ' ').replace(/\s+-\s+/g, ' ');
reply = reply.toLowerCase().replace(/[ \t]{2,}/g, ' ').trim();
if (!reply) { reply = 'hey you'; }
const bm = $('Build Messages').first().json;
return [{ json: { reply: reply, fan_id: bm.fan_id, bot_id: bm.bot_id } }];

const ctx = $('DB: ingest').first().json || {};
const fr = $('Format Reply').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
const lines = recent.map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; });
lines.push('her: ' + (fr.reply || ''));
const convo = lines.join('\n');
const prevNote = (ctx.summary && ctx.summary.length) ? ctx.summary : 'none';
const sys = [
'you are an expert conversion strategist for an adult creator dm funnel. candace is a flirty creator who chats with men in her dms and funnels them to her private telegram @candace_summers. you read the conversation and produce an honest, accurate, unsentimental read of THIS man: his buying intent, where he is in the funnel, his type, and the exact technique to convert him. you are accurate, not optimistic. output one json object only.',
'output exactly this json:',
'{',
'"intent_score": integer 0 to 100 by the rubric,',
'"stage": one of [cold, rapport, warming, hooked, funnelled, converted, lost],',
'"buyer_type": one of [provider, baller, submissive, lonely, romantic, tire_kicker, normal],',
'"temperature": one of [cold, warm, hot],',
'"signals": array of short evidence phrases taken from the actual conversation,',
'"technique": one short line, the best technique to move him closer to converting from here,',
'"next_move": one short line, the specific next thing candace should do,',
'"note": two short sentences candace should remember about him, who he is and where things stand',
'}',
'intent_score rubric: 0-20 cold or tire kicker, low effort or skeptical, no real interest. 21-40 mild, casual chatting, no buying signals. 41-60 warming, engaged and complimenting and putting in effort. 61-80 hot, strong hooks like jealousy, calls her special or different, future talk, hints at wanting more, or spend or provider signals. 81-100 ready, explicitly asked for more or onlyfans or where to find her, eager, said he would spend or spoil her, or heading to or joined the telegram.',
'stage: cold=just started. rapport=casual chatting. warming=clear interest building. hooked=clearly into her. funnelled=she has given him the telegram. converted=he has gone to or joined the telegram. lost=cold hostile or gone.',
'technique by type: provider or baller, make him feel like the man and let him invest, funnel as exclusive access. submissive, dominate and make him earn it, funnel as a privilege. lonely or romantic, build emotional intimacy and girlfriend energy, funnel as getting closer. tire_kicker, do not over invest, keep light, let him go if no movement.'
].join('\n');
const usr = 'previous notes on him: ' + prevNote + '\nconversation so far (oldest first):\n' + convo + '\noutput the json now.';
return [{ json: { profileMessages: [{ role: 'system', content: sys }, { role: 'user', content: usr }], fan_id: ctx.fan_id, reply: (fr.reply || '') } }];

const d = $json || {};
let p = {};
try { const raw = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : '{}'; p = JSON.parse(raw); } catch (e) { p = {}; }
const src = $('Build Profile Request').first().json || {};
const fan_id = src.fan_id;
const reply = src.reply || '';
let stage = p.stage || 'rapport';
if (/candace_summers|telegram/i.test(reply) && stage !== 'converted') stage = 'funnelled';
const note = (p.note && String(p.note).length) ? p.note : 'still building rapport.';
const buyer = p.buyer_type || null;
const score = (typeof p.intent_score === 'number') ? p.intent_score : null;
const interaction = ($('Extract Inbound').first().json.interaction) || null;
const metadata = { intent_score: score, stage: stage, buyer_type: buyer, temperature: p.temperature || null, signals: Array.isArray(p.signals) ? p.signals : [], technique: p.technique || null, next_move: p.next_move || null, last_interaction_ts: interaction };
return [{ json: { fan_id: fan_id, summary: note, stage: stage, buyer_type: buyer, metadata: metadata } }];
